import { useState } from "react";
import { createPortal } from "react-dom";
import { createPost } from "../firebase/posts";
import { generateBlog } from "../ai/aiService";
import toast from "react-hot-toast";

export default function WriteModal({ onClose, onPublished, isDemo, onDemoPublish }) {
  const [form, setForm] = useState({
    title: "",
    content: "",
  });

  const [aiDraft, setAiDraft] = useState("");
  const [loading, setLoading] = useState(false);

  const set = (k, v) => setForm((f) => ({ ...f, [k]: v }));

  // 🔥 AI GENERATE
  const handleGenerate = async () => {
    if (!form.title.trim()) {
      toast.error("Enter title first");
      return;
    }

    setLoading(true);
    toast.loading("Generating AI content...");

    try {
      const content = await generateBlog(form.title);

      setAiDraft(content);

      toast.dismiss();
      toast.success("AI content ready!");
    } catch {
      toast.dismiss();
      toast.error("AI failed");
    }

    setLoading(false);
  };

  // 🔥 USE AI CONTENT
  const handleUse = () => {
    setForm((f) => ({ ...f, content: aiDraft }));
    setAiDraft("");
  };

  // 🔥 PUBLISH
  const handlePublish = async () => {
    if (!form.title || !form.content) {
      toast.error("Fill all fields");
      return;
    }

    const postData = { ...form };

    if (isDemo) {
      onDemoPublish?.(postData);
    } else {
      await createPost(postData);
    }

    toast.success("Post published!");
    onPublished?.();
    onClose();
  };

  return createPortal(
    <div style={s.backdrop}>
      <div style={s.modal}>
        {/* CLOSE */}
        <button style={s.closeBtn} onClick={onClose}>
          ✕
        </button>

        <h2 style={s.title}>✍️ Write Post</h2>

        {/* INPUT */}
        <input
          style={s.input}
          placeholder="Enter title..."
          value={form.title}
          onChange={(e) => set("title", e.target.value)}
        />

        {/* TEXTAREA */}
        <textarea
          style={s.textarea}
          placeholder="Write your content..."
          value={form.content}
          onChange={(e) => set("content", e.target.value)}
        />

        {/* AI BUTTON */}
        <button style={s.primaryBtn} onClick={handleGenerate}>
          ✨ Generate Blog with AI
        </button>

        {/* AI PREVIEW */}
        {aiDraft && (
          <div style={s.preview}>
            <h4 style={s.previewTitle}>🤖 AI Draft</h4>

            <div style={s.previewText}>{aiDraft}</div>

            <div style={s.actions}>
              <button style={s.useBtn} onClick={handleUse}>
                ✅ Use
              </button>

              <button style={s.secondaryBtn} onClick={handleGenerate}>
                🔄 Regenerate
              </button>

              <button style={s.closeSmall} onClick={() => setAiDraft("")}>
                ❌ Close
              </button>
            </div>
          </div>
        )}

        {/* PUBLISH */}
        <button style={s.publishBtn} onClick={handlePublish}>
          🚀 Publish
        </button>
      </div>
    </div>,
    document.body // 🔥 PORTAL FIX (CRITICAL)
  );
}

const s = {
  backdrop: {
    position: "fixed",
    top: 0,
    left: 0,
    width: "100vw",
    height: "100vh",
    background: "rgba(0,0,0,0.6)",
    backdropFilter: "blur(6px)",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    zIndex: 999999, // 🔥 always on top
  },

  modal: {
    background: "#ffffff",
    padding: 24,
    borderRadius: 16,
    width: 520,
    position: "relative",
    zIndex: 1000000,
    boxShadow: "0 20px 60px rgba(0,0,0,0.3)",
  },

  closeBtn: {
    position: "absolute",
    top: 10,
    right: 10,
    border: "none",
    background: "#f1f5f9",
    borderRadius: "50%",
    width: 32,
    height: 32,
    cursor: "pointer",
  },

  title: {
    fontSize: "1.5rem",
    fontWeight: 700,
    marginBottom: 14,
  },

  input: {
    width: "100%",
    padding: 12,
    borderRadius: 10,
    border: "1px solid #e5e7eb",
    marginBottom: 12,
  },

  textarea: {
    width: "100%",
    height: 140,
    padding: 12,
    borderRadius: 10,
    border: "1px solid #e5e7eb",
    marginBottom: 14,
    lineHeight: 1.5,
  },

  primaryBtn: {
    width: "100%",
    padding: 12,
    borderRadius: 12,
    background: "linear-gradient(135deg,#2563eb,#1d4ed8)",
    color: "#fff",
    fontWeight: 600,
    border: "none",
    marginBottom: 12,
    cursor: "pointer",
    boxShadow: "0 6px 20px rgba(37,99,235,0.3)",
  },

  preview: {
    border: "1px solid #e5e7eb",
    borderRadius: 12,
    padding: 12,
    marginBottom: 14,
    background: "#f8fafc",
  },

  previewTitle: {
    marginBottom: 8,
    fontWeight: 600,
  },

  previewText: {
    maxHeight: 150,
    overflow: "auto",
    marginBottom: 10,
    lineHeight: 1.6,
  },

  actions: {
    display: "flex",
    gap: 8,
  },

  useBtn: {
    flex: 1,
    background: "#16a34a",
    color: "#fff",
    border: "none",
    borderRadius: 10,
    padding: 10,
    fontWeight: 600,
    cursor: "pointer",
  },

  secondaryBtn: {
    flex: 1,
    borderRadius: 10,
    padding: 10,
    border: "1px solid #e5e7eb",
    background: "#fff",
    cursor: "pointer",
  },

  closeSmall: {
    flex: 1,
    borderRadius: 10,
    padding: 10,
    border: "1px solid #e5e7eb",
    background: "#fff",
    cursor: "pointer",
  },

  publishBtn: {
    width: "100%",
    padding: 12,
    borderRadius: 12,
    background: "#1d4ed8",
    color: "#fff",
    fontWeight: 600,
    border: "none",
    cursor: "pointer",
  },
};
